/**
 * 任务相关 — 仅处理世界书 `strategy.type`（蓝 constant / 绿 selective）
 *
 * 与「关键字动态世界书」独立；不含「地点-午夜玫瑰酒馆」等逻辑。
 *
 * 规则摘要：
 * 1. 仅在「委托结算安全地点」且输入框含发布类关键字 →「委托发布」蓝灯；同时当前「猎人等级」对应「猎人等级-*」蓝灯。松手后按末楼 id 再维持 2 楼后转绿。离开安全地点立即取消粘滞并转绿。
 * 2. 变量「委托状态」为「执行中」→「当前委托状态」蓝；否则绿。
 * 3. 输入框含「接受委托」→「委托承接」蓝，粘滞 2 楼。
 * 4. 输入框含「委托结算」→「委托结算」蓝，粘滞 2 楼；猎人等级当前档条目同步蓝（与关键字动态世界书里 lastHit 思路一致，此处按输入框+粘滞）。
 */

// ========== 可按需修改 ==========

/** 规则 1：输入框内出现任一字串即视为「要看委托」（须同时在安全地点） */
const QUEST_PUBLISH_DRAFT_KEYWORDS = ['委托', '需要委托', '看看委托', '发布委托'];

/** 规则 3 */
const ACCEPT_QUEST_DRAFT_KEYWORDS = ['接受委托'];

/** 规则 4 */
const SETTLEMENT_DRAFT_KEYWORDS = ['委托结算'];

/** 世界书条目名需包含的片段 */
const ENTRY_PUBLISH = '委托发布';
const ENTRY_ACCEPT = '委托承接';
const ENTRY_SETTLEMENT = '委托结算';
const ENTRY_QUEST_STATUS = '当前委托状态';
const ENTRY_MONSTER_ATTR_PREFIX = '怪物属性·';
const QUEST_EXECUTING = '执行中';
const MONSTER_ATTRS = ['山', '泽', '空', '炎', '虚'] as const;

/** 粘滞「两楼」：以 `getLastMessageId()` 为锚，>= anchor + FLOOR_STICKY_DELTA 后转绿 */
const FLOOR_STICKY_DELTA = 2;

const DEBOUNCE_MS = 450;
const DRAFT_POLL_MS = 600;

const HIT_TYPE = 'constant' as const;
const MISS_TYPE = 'selective' as const;

const DEBUG = false;
const LOG_PREFIX = '[任务相关世界书]';

const TEXTAREA_SELECTORS =
  '#send_textarea, textarea[name="send_textarea"], textarea#send_textarea, #send_text, textarea[data-testid="send_textarea"], textarea.mes_textarea';

const VARIABLE_SCOPES: Array<{ type: Parameters<typeof getVariables>[0]['type']; message_id?: number | string }> = [
  { type: 'message', message_id: 'latest' },
  { type: 'chat' },
  { type: 'character' },
  { type: 'global' },
];

const HUNTER_RANKS = new Set(['D', 'C', 'B', 'A', 'S', 'SS']);

// ========== 状态：粘滞锚点（末楼 message_id）==========
let publishStickyAnchor = -1;
let acceptStickyAnchor = -1;
let settlementStickyAnchor = -1;

function log(...args: unknown[]): void {
  if (!DEBUG) return;
  console.info(LOG_PREFIX, ...args);
}

function readWorldFieldFromCandidate(candidate: any, key: string): unknown {
  return (
    candidate?.stat_data?.世界?.[key] ??
    candidate?.stat_data?.stat_data?.世界?.[key] ??
    candidate?.世界?.[key] ??
    candidate?.mvu?.世界?.[key]
  );
}

function readWorldField(key: string): unknown {
  const g = globalThis as any;
  try {
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      const latest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' }) ?? {};
      const v = readWorldFieldFromCandidate(latest, key);
      if (v !== undefined && v !== null) return v;
      const mid = getLastMessageId();
      if (mid >= 0) {
        const byMid = g.Mvu.getMvuData({ type: 'message', message_id: mid });
        const v2 = readWorldFieldFromCandidate(byMid, key);
        if (v2 !== undefined && v2 !== null) return v2;
      }
    }
  } catch {
    /* ignore */
  }
  for (const scope of VARIABLE_SCOPES) {
    try {
      const v = readWorldFieldFromCandidate(getVariables(scope as any) as any, key);
      if (v !== undefined && v !== null) return v;
    } catch {
      /* ignore */
    }
  }
  return undefined;
}

function readWorldString(key: string): string {
  const raw = readWorldField(key);
  if (raw === undefined || raw === null) return '';
  return String(raw).trim();
}

function getWorldLocationValue(): string {
  const loc =
    readWorldString('当前位置') ||
    readWorldString('当前地点');
  return loc;
}

function normalizeSettlementPlaces(raw: unknown): string[] {
  if (raw === undefined || raw === null) return [];
  if (Array.isArray(raw)) {
    return raw.map(x => String(x ?? '').trim()).filter(Boolean);
  }
  const s = String(raw).trim();
  if (!s) return [];
  return [s];
}

function getSettlementSafePlaces(): string[] {
  return normalizeSettlementPlaces(readWorldField('委托结算安全地点'));
}

function locationMatchesSafePlace(worldLoc: string, place: string): boolean {
  if (!worldLoc || !place) return false;
  return worldLoc.includes(place) || place.includes(worldLoc);
}

function isAtSettlementSafeLocation(): boolean {
  const loc = getWorldLocationValue();
  const places = getSettlementSafePlaces();
  if (!loc || places.length === 0) return false;
  return places.some(p => locationMatchesSafePlace(loc, p));
}

function readQuestExecutionStatus(): string {
  const keys = ['委托状态', '当前委托状态', '委托执行状态'] as const;
  for (const k of keys) {
    const v = readWorldString(k);
    if (v) return v;
  }
  return '';
}

function hasCurrentQuestLikeDarkPanel(): boolean {
  const grade = readWorldString('当前委托等级');
  const location = readWorldString('当前委托地点');
  return Boolean(grade && location);
}

function readMonsterAttrRaw(): string {
  const keys = ['当前委托怪物属性', '怪物属性', '当前怪物属性'] as const;
  for (const k of keys) {
    const v = readWorldString(k);
    if (v) return v;
  }
  return '';
}

function normalizeMonsterAttr(raw: string): (typeof MONSTER_ATTRS)[number] | '' {
  const t = String(raw || '').trim();
  if (!t) return '';
  // 常见写法：'山'、'山/泽'、'山(…)'、'当前：山'
  const first = t
    .replace(/^[^山泽空炎虚]*([山泽空炎虚]).*$/u, '$1')
    .trim();
  return (MONSTER_ATTRS as readonly string[]).includes(first) ? (first as any) : '';
}

function readHunterRankLetter(): string {
  const r = readWorldString('猎人等级').toUpperCase();
  if (HUNTER_RANKS.has(r)) return r;
  return 'D';
}

function readTopSendTextareaText(): string {
  try {
    const doc = window.top?.document;
    if (!doc) return '';
    const el = doc.querySelector(TEXTAREA_SELECTORS) as HTMLTextAreaElement | null;
    if (!el) return '';
    return String(el.value ?? '');
  } catch {
    return '';
  }
}

function draftHasAnyKeyword(text: string, keywords: string[]): boolean {
  if (!text) return false;
  return keywords.some(k => k && text.includes(k));
}

function getLastMessageIdSafe(): number {
  try {
    return getLastMessageId();
  } catch {
    return -1;
  }
}

/** 无楼层时 id 为 -1，粘滞锚点用 0，避免首条消息发出后立刻丢蓝 */
function anchorMessageIdForSticky(): number {
  const m = getLastMessageIdSafe();
  return m >= 0 ? m : 0;
}

/** 非激活时：锚点有效且末楼 id 尚未 +FLOOR_STICKY_DELTA → 仍蓝 */
function stickyAfterDraftOff(anchor: number): { blue: boolean; anchor: number } {
  const mid = getLastMessageIdSafe();
  if (anchor < 0) return { blue: false, anchor: -1 };
  if (mid < 0) return { blue: true, anchor };
  if (mid < anchor + FLOOR_STICKY_DELTA) return { blue: true, anchor };
  return { blue: false, anchor: -1 };
}

function getPrimaryWorldbookName(): string | null {
  try {
    const { primary } = getCharWorldbookNames('current');
    const n = primary?.trim();
    return n ? n : null;
  } catch {
    return null;
  }
}

let debounceTimer: ReturnType<typeof setTimeout> | null = null;

function scheduleSync(): void {
  if (debounceTimer) clearTimeout(debounceTimer);
  debounceTimer = setTimeout(() => {
    debounceTimer = null;
    void errorCatched(syncQuestWorldbook)();
  }, DEBOUNCE_MS);
}

function resetStickyState(): void {
  publishStickyAnchor = -1;
  acceptStickyAnchor = -1;
  settlementStickyAnchor = -1;
}

async function syncQuestWorldbook(): Promise<void> {
  const wbName = getPrimaryWorldbookName();
  if (!wbName) {
    console.warn(LOG_PREFIX, '当前角色未绑定主世界书 primary，已跳过');
    return;
  }

  const draft = readTopSendTextareaText();
  const atSafe = isAtSettlementSafeLocation();
  const publishDraftHit = draftHasAnyKeyword(draft, QUEST_PUBLISH_DRAFT_KEYWORDS);
  const publishActive = atSafe && publishDraftHit;

  let publishBlue: boolean;
  if (!atSafe) {
    publishStickyAnchor = -1;
    publishBlue = false;
  } else if (publishActive) {
    publishStickyAnchor = anchorMessageIdForSticky();
    publishBlue = true;
  } else {
    const st = stickyAfterDraftOff(publishStickyAnchor);
    publishStickyAnchor = st.anchor;
    publishBlue = st.blue;
  }

  const acceptAct = draftHasAnyKeyword(draft, ACCEPT_QUEST_DRAFT_KEYWORDS);
  let acceptBlue: boolean;
  if (acceptAct) {
    acceptStickyAnchor = anchorMessageIdForSticky();
    acceptBlue = true;
  } else {
    const st = stickyAfterDraftOff(acceptStickyAnchor);
    acceptStickyAnchor = st.anchor;
    acceptBlue = st.blue;
  }

  const settleAct = draftHasAnyKeyword(draft, SETTLEMENT_DRAFT_KEYWORDS);
  let settlementBlue: boolean;
  if (settleAct) {
    settlementStickyAnchor = anchorMessageIdForSticky();
    settlementBlue = true;
  } else {
    const st = stickyAfterDraftOff(settlementStickyAnchor);
    settlementStickyAnchor = st.anchor;
    settlementBlue = st.blue;
  }

  const questStatus = readQuestExecutionStatus();
  // 与 Dark 面板保持一致：
  // 当「委托状态」为空但已存在当前委托（等级+地点）时，视为执行中。
  const questExecuting = questStatus === QUEST_EXECUTING || (!questStatus && hasCurrentQuestLikeDarkPanel());
  const monsterAttr = normalizeMonsterAttr(readMonsterAttrRaw());

  const hunterLetter = readHunterRankLetter();
  const hunterEntryToken = `猎人等级-${hunterLetter}`;

  log({
    atSafe,
    publishActive,
    publishBlue,
    acceptBlue,
    settlementBlue,
    questStatus,
    questExecuting,
    monsterAttr,
    hunterEntryToken,
    anchors: { publishStickyAnchor, acceptStickyAnchor, settlementStickyAnchor },
  });

  await updateWorldbookWith(wbName, entries => {
    for (const entry of entries) {
      const name = entry?.name ?? '';
      if (!name) continue;
      if (entry.strategy?.type === 'vectorized') continue;

      // ========= 新增：自动开启/关闭（不走蓝绿灯、不依赖 entry.enabled） =========
      // 1) 委托执行中：开启「当前委托状态」；否则关闭
      if (name.includes(ENTRY_QUEST_STATUS)) {
        const nextEnabled = questExecuting;
        if (entry.enabled !== nextEnabled) {
          entry.enabled = nextEnabled;
        }
        continue;
      }

      // 2) 委托执行中：按当前怪物属性开启对应「怪物属性·X」；否则全关
      if (name.includes(ENTRY_MONSTER_ATTR_PREFIX)) {
        const hitAttr = (MONSTER_ATTRS as readonly string[]).find(attr =>
          name.includes(`${ENTRY_MONSTER_ATTR_PREFIX}${attr}`),
        );
        if (hitAttr) {
          const nextEnabled = questExecuting && monsterAttr === hitAttr;
          if (entry.enabled !== nextEnabled) {
            entry.enabled = nextEnabled;
          }
          continue;
        }
      }

      // ========= 旧逻辑：蓝绿灯（只对当前已启用条目生效，避免把其它条目“点亮”） =========
      if (!entry.enabled) continue;

      let next: typeof HIT_TYPE | typeof MISS_TYPE | null = null;

      if (name.includes(ENTRY_PUBLISH)) {
        next = publishBlue ? HIT_TYPE : MISS_TYPE;
      } else if (name.includes(ENTRY_ACCEPT)) {
        next = acceptBlue ? HIT_TYPE : MISS_TYPE;
      } else if (name.includes(ENTRY_SETTLEMENT)) {
        next = settlementBlue ? HIT_TYPE : MISS_TYPE;
      } else if (name.includes('猎人等级-')) {
        next =
          (publishBlue || settlementBlue) && name.includes(hunterEntryToken) ? HIT_TYPE : MISS_TYPE;
      } else {
        continue;
      }

      if (entry.strategy.type === next) continue;
      entry.strategy = { ...entry.strategy, type: next };
    }
    return entries;
  });
}

function bindTopSendTextareaHooks(): void {
  try {
    const doc = window.top?.document;
    if (!doc) return;
    const textarea = doc.querySelector(TEXTAREA_SELECTORS) as HTMLTextAreaElement | null;
    if (!textarea) return;
    const mark = '__questRelatedWbBound__';
    if ((textarea as any)[mark]) return;
    (textarea as any)[mark] = true;
    const onChange = () => scheduleSync();
    textarea.addEventListener('input', onChange);
    textarea.addEventListener('paste', onChange);
    textarea.addEventListener('cut', onChange);
    textarea.addEventListener('keydown', (ev: KeyboardEvent) => {
      if (ev.key !== 'Enter') return;
      if (ev.shiftKey || ev.ctrlKey || ev.altKey) return;
      onChange();
    });
    onChange();
  } catch {
    /* ignore */
  }
}

function startDraftPoll(): void {
  const k = '__questRelatedWbDraftPoll__';
  if ((globalThis as any)[k]) return;
  let last = '';
  (globalThis as any)[k] = setInterval(() => {
    const t = readTopSendTextareaText();
    if (t === last) return;
    last = t;
    scheduleSync();
  }, DRAFT_POLL_MS);
}

function exposeDebug(): void {
  const g = globalThis as any;
  g.__questWbDump = () => {
    const o = {
      primary: getPrimaryWorldbookName(),
      当前位置: getWorldLocationValue(),
      委托结算安全地点: getSettlementSafePlaces(),
      atSafe: isAtSettlementSafeLocation(),
      draftPreview: readTopSendTextareaText().slice(0, 160),
      委托状态: readQuestExecutionStatus(),
      猎人等级: readHunterRankLetter(),
      anchors: { publishStickyAnchor, acceptStickyAnchor, settlementStickyAnchor },
    };
    console.info(LOG_PREFIX, '__questWbDump', o);
    return o;
  };
  try {
    if (window.top && window.top !== window) (window.top as any).__questWbDump = g.__questWbDump;
  } catch {
    /* cross-origin */
  }
}

$(() => {
  errorCatched(() => {
    exposeDebug();
    bindTopSendTextareaHooks();
    startDraftPoll();

    void syncQuestWorldbook();

    eventOn(tavern_events.MESSAGE_SENT, scheduleSync);
    eventOn(tavern_events.MESSAGE_RECEIVED, scheduleSync);
    eventOn(tavern_events.MESSAGE_UPDATED, scheduleSync);
    eventOn(tavern_events.CHAT_CHANGED, () => {
      resetStickyState();
      scheduleSync();
    });
    eventOn(tavern_events.CHARACTER_PAGE_LOADED, scheduleSync);

    const onDarkResync = () => scheduleSync();
    $(window).on('dark_worldbook_resync_needed', onDarkResync);
    $(document).on('dark_worldbook_resync_needed', onDarkResync);

    $(window).on('pagehide', () => {
      if (debounceTimer) {
        clearTimeout(debounceTimer);
        debounceTimer = null;
      }
    });

    console.info(LOG_PREFIX, '已加载');
  })();
});
